class Solution {
    public String reformatNumber(String number) {
        number = number.replaceAll("[ -]", "");
        StringBuilder res = new StringBuilder();
        int len = number.length();
        int idx = 0;
        while (len > 4) {
            res.append(number.substring(idx, idx + 3) + "-");
            idx += 3;
            len -= 3;
        }
        if (len == 4) {
            res.append(number.substring(idx, idx + 2) + "-" + number.substring(idx + 2));
        } else {
            res.append(number.substring(idx));
        }
        return res.toString();
    }
}
